// Prepara el payload para RunPod
const email = $input.first().json;

const asunto = email.subject || '';
const remitente = email.from?.value?.[0]?.address || email.from || '';
const cuerpo = email.text || email.snippet || '';
const fecha = email.date || new Date().toISOString();
const tieneAdjuntos = (email.attachments || []).length > 0;
const adjuntos = (email.attachments || []).map(a => a.name || a.filename || '').join(', ');

const prompt = `Eres un asistente de una promotoría de seguros GNP. Analiza este correo y extrae la información del trámite en formato JSON.

CORREO:
De: ${remitente}
Asunto: ${asunto}
Fecha: ${fecha}
Adjuntos: ${adjuntos || 'ninguno'}
Cuerpo:
${cuerpo.substring(0, 2000)}

Extrae y devuelve SOLO un JSON con esta estructura exacta (sin texto adicional):
{
  "ramo": "Vida|GMM|PyMES|Autos|Desconocido",
  "tipoTramite": "Emision|Endoso|Siniestro|Renovacion|Cancelacion|Desconocido",
  "nombreAgente": "nombre del agente o remitente",
  "emailAgente": "email del remitente",
  "claveAgente": "clave GNP si se menciona, sino null",
  "nombreAsegurado": "nombre del asegurado si se menciona, sino null",
  "numeroPoliza": "numero de poliza si se menciona, sino null",
  "monto": "monto en numeros si se menciona, sino null",
  "prioridad": "Normal|Alta|Urgente",
  "resumen": "resumen de 1 oracion del tramite",
  "documentosAdjuntos": ["lista de documentos adjuntos"],
  "accionRequerida": "que debe hacer el analista"
}`;

return [{
  json: {
    prompt,
    emailOriginal: {
      remitente,
      asunto,
      fecha,
      cuerpo: cuerpo.substring(0, 3000),
      tieneAdjuntos,
      adjuntos: email.attachments || []
    }
  }
}];

// Parsear la respuesta de RunPod (Phi-3 via Ollama)
const runpodResponse = $input.first().json;
const emailOriginal = $('Preparar Prompt').first().json.emailOriginal;

let tramiteData = {};

try {
  // El output de Ollama viene en output[0].choices[0].text
  const rawText = runpodResponse?.output?.[0]?.choices?.[0]?.text || '';

  // Extraer el JSON de la respuesta (puede tener texto antes/después)
  const jsonMatch = rawText.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    tramiteData = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error('No se encontró JSON en la respuesta');
  }
} catch (e) {
  // Fallback si el modelo no devuelve JSON válido
  tramiteData = {
    ramo: 'Desconocido',
    tipoTramite: 'Desconocido',
    nombreAgente: emailOriginal.remitente,
    emailAgente: emailOriginal.remitente,
    claveAgente: null,
    nombreAsegurado: null,
    numeroPoliza: null,
    monto: null,
    prioridad: 'Normal',
    resumen: emailOriginal.asunto,
    documentosAdjuntos: [],
    accionRequerida: 'Revisar manualmente'
  };
}

// Generar folio interno
const ahora = new Date();
const folio = `TRM-${ahora.getFullYear()}${String(ahora.getMonth()+1).padStart(2,'0')}${String(ahora.getDate()).padStart(2,'0')}-${Math.random().toString(36).substr(2,6).toUpperCase()}`;

return [{
  json: {
    folio,
    ...tramiteData,
    canalIngreso: 'Correo',
    estatus: 'RECIBIDO',
    fechaIngreso: emailOriginal.fecha || ahora.toISOString(),
    emailOriginal,
    runpodJobId: $('RunPod: Enviar Job').first().json.id,
    procesadoEn: ahora.toISOString()
  }
}];

// Log del resultado final
const tramite = $('Parsear Respuesta IA').first().json;
const supabaseResult = $input.first().json;

console.log(`✅ Trámite procesado: ${tramite.folio}`);
console.log(`   Ramo: ${tramite.ramo} | Tipo: ${tramite.tipoTramite}`);
console.log(`   Agente: ${tramite.nombreAgente}`);
console.log(`   Prioridad: ${tramite.prioridad}`);
console.log(`   Supabase ID: ${supabaseResult?.[0]?.id || 'N/A'}`);

return [{
  json: {
    exito: true,
    folio: tramite.folio,
    ramo: tramite.ramo,
    tipoTramite: tramite.tipoTramite,
    agente: tramite.nombreAgente,
    prioridad: tramite.prioridad,
    supabaseId: supabaseResult?.[0]?.id,
    mensaje: `Trámite ${tramite.folio} creado exitosamente`
  }
}];
